(1047, '1117733522', '1117733522', '27190 Columbia Street', '92544', '', 'Columbia', 'Hemet', 'CA', 'Residential', 'SingleFamilyResidence', 4, 2.0, '10890', 2, 'One', 489000, 1774, '2026-03-19 10:42:47', '2025-06-19', 33.726768000000000, -116.945109000000000, 'MAGGIE', 'RAMIREZ-GARCIA', 'Active', 'Vista Sotheby\'s International Realty', 'This unique home is in the heart of Hemet.  offering 4 bedrooms 2 bath. The Kitchen is spacious with granite counters lots of cabinets. Primary bedroom is on the opposite side of the other bedrooms giving privacy. There is a brick fireplace in the dining area. There is laminate wood flooring throughout the home. The home is on a lot of over 10,000 square feet. Plenty of room for entertainment. There are approximately 30 solar panels that will be paid off at the close of escrow. This home has lots of potential.', '[\"https:\\/\\/api.cotality.com\\/trestle\\/Media\\/Property\\/PHOTO-Jpeg\\/1117733522\\/1\\/ODU2My84NTc1LzIw\\/MjAvMTcwMjMvMTc3Mzk0MjQ5NA\\/HvAVR4UDdFDD2gQTuu8Iq4FwQLbrcqJfz5gPft4zLHk\"]', '2025-06-19 15:13:44', 1, 'Laminate,Tile,Vinyl', '1', '', 267, NULL, '1', '', 1973, '1', 4, '', 'Hemet Unified', 0, 'AverageCondition', '2026-03-19 17:48:15', '0000-00-00 00:00:00', 0, 'SquareFeet', 'Assessor', 'SquareFeet', 'Feet', 0, 0, 0, 1, 'Dishwasher,Disposal,GasRange,Microwave', 0, 0, 1, 1, 1, 0, 0, 267, 267, NULL, 1, NULL, 1, 1, NULL, 0.2500, 10890.00, 10890.00, '2025-11-05 00:52:34', '2025-11-05 00:52:34', NULL, '2025-06-19 01:56:46', '2025-06-19', '2025-11-05', '2026-03-19', '951-684-1300', 'howard.wood@vistasir.com', 'mrgteam07@gmail.com', '951-329-9119', 'InlandValleys', 'MAGGIE RAMIREZ-GARCIA', '', '17155849', '450031005', 'urn:reso:upi:2.0:US:06065:450031005', '3', 'Riverside', 'HEMET', '06065', NULL, NULL, NULL, 'None', 'NoCommonWalls', 'SingleFamilyResidence', 'Active', 'Expired', 'House', NULL, NULL, 'CentralAir', 'Central', 'Public', NULL, 'Mountains', 'DiningRoom', 'Standard', 'SeparateFormalDiningRoom,GraniteCounters,